PROGRAM TankLevelMonitor
VAR_INPUT
    RawLevel : INT;
    HighAlarmSP : REAL;
    LowAlarmSP : REAL;
    Hysteresis : REAL;
END_VAR

VAR_OUTPUT
    LevelPct : REAL;
    HighAlarm : BOOL;
    LowAlarm : BOOL;
END_VAR

VAR
    _HighAlarmSP : REAL := 85.0;
    _LowAlarmSP : REAL := 15.0;
    _Hysteresis : REAL := 2.0;
    HighAlarmLatch : BOOL := FALSE;
    LowAlarmLatch : BOOL := FALSE;
END_VAR

// Use input values if provided, otherwise use defaults
IF HighAlarmSP <> 0.0 THEN
    _HighAlarmSP := HighAlarmSP;
END_IF;

IF LowAlarmSP <> 0.0 THEN
    _LowAlarmSP := LowAlarmSP;
END_IF;

IF Hysteresis <> 0.0 THEN
    _Hysteresis := Hysteresis;
END_IF;

// Calculate Level Percentage
// AI 0..27648 -> 0..100%
LevelPct := REAL(RawLevel) / 276.48;

// High Alarm with Hysteresis
// Turn ON if LevelPct >= HighAlarmSP
// Turn OFF if LevelPct < HighAlarmSP - Hysteresis
IF LevelPct >= _HighAlarmSP THEN
    HighAlarmLatch := TRUE;
ELSIF LevelPct < (_HighAlarmSP - _Hysteresis) THEN
    HighAlarmLatch := FALSE;
END_IF;
HighAlarm := HighAlarmLatch;

// Low Alarm with Hysteresis
// Turn ON if LevelPct <= LowAlarmSP
// Turn OFF if LevelPct > LowAlarmSP + Hysteresis
IF LevelPct <= _LowAlarmSP THEN
    LowAlarmLatch := TRUE;
ELSIF LevelPct > (_LowAlarmSP + _Hysteresis) THEN
    LowAlarmLatch := FALSE;
END_IF;
LowAlarm := LowAlarmLatch;

END_PROGRAM

PROGRAM MotorStarDelta
VAR_INPUT
    Start_btn: BOOL;
    Stop_btn: BOOL;
    Overload: BOOL;
END_VAR
VAR_OUTPUT
    Main_Contactor: BOOL;
    Star_Contactor: BOOL;
    Delta_Contactor: BOOL;
    Fault: BOOL;
END_VAR
VAR
    Start_Rising: R_TRIG;
    MotorRunning: BOOL;
    TimerStarDelta: TON;
END_VAR

(* Rising edge detection for Start_btn *)
Start_Rising(CLK := Start_btn);

(* Motor running latch: set on start edge, reset on stop or fault *)
IF Stop_btn OR Overload THEN
    MotorRunning := FALSE;
ELSIF Start_Rising.Q AND NOT Stop_btn AND NOT Overload THEN
    MotorRunning := TRUE;
END_IF;

(* Star-Delta transition timer: 3 seconds *)
TimerStarDelta(IN := MotorRunning, PT := T#3s);

(* Output logic with hardware interlock *)
Main_Contactor := MotorRunning;
Star_Contactor := MotorRunning AND NOT TimerStarDelta.Q AND NOT Delta_Contactor;
Delta_Contactor := MotorRunning AND TimerStarDelta.Q AND NOT Star_Contactor;

(* Fault indication *)
Fault := Overload;

END_PROGRAM

TYPE
    ConveyorState : (ST_IDLE, ST_RUNNING, ST_REJECTING, ST_FAULT);
END_TYPE

PROGRAM SortingConveyor
VAR_INPUT
    StartCmd : BOOL;
    SensorPresent : BOOL;
    SensorDefect : BOOL;
    EStop : BOOL;
END_VAR

VAR_OUTPUT
    MotorRun : BOOL;
    RejectSolenoid : BOOL;
END_VAR

VAR
    CurrentState : ConveyorState := ST_IDLE;
    NextState : ConveyorState;
    RejectTimer : TON;
END_VAR

CASE CurrentState OF
    ST_IDLE:
        MotorRun := FALSE;
        RejectSolenoid := FALSE;
        IF EStop THEN
            NextState := ST_FAULT;
        ELSIF StartCmd THEN
            NextState := ST_RUNNING;
        END_IF;

    ST_RUNNING:
        MotorRun := TRUE;
        RejectSolenoid := FALSE;
        IF EStop THEN
            NextState := ST_FAULT;
        ELSIF SensorPresent AND SensorDefect THEN
            NextState := ST_REJECTING;
        END_IF;

    ST_REJECTING:
        MotorRun := FALSE;
        RejectSolenoid := TRUE;
        RejectTimer(IN := TRUE, PT := T#500MS);
        IF EStop THEN
            NextState := ST_FAULT;
        ELSIF RejectTimer.Q THEN
            NextState := ST_RUNNING;
        END_IF;

    ST_FAULT:
        MotorRun := FALSE;
        RejectSolenoid := FALSE;
        IF NOT EStop THEN
            NextState := ST_IDLE;
        END_IF;
END_CASE;

CurrentState := NextState;
END_PROGRAM

FUNCTION_BLOCK PID_Temperature
VAR_INPUT
    Enable : BOOL;
    Setpoint : REAL;
    ProcessValue : REAL;
    Kp : REAL := 2.0;
    Ki : REAL := 0.05;
    Kd : REAL := 0.0;
    CycleTime : TIME := T#100ms;
END_VAR
VAR_OUTPUT
    Output : REAL;
END_VAR
VAR
    Error : REAL;
    ErrorPrev : REAL;
    IntegralTerm : REAL;
    DerivativeTerm : REAL;
    Ts : REAL;
END_VAR

Ts := TIME_TO_REAL(CycleTime);

IF NOT Enable THEN
    Output := 0.0;
    IntegralTerm := 0.0;
    ErrorPrev := 0.0;
ELSE
    Error := Setpoint - ProcessValue;
    IntegralTerm := IntegralTerm + Ki * Ts * Error;
    DerivativeTerm := Kd * (Error - ErrorPrev) / Ts;
    Output := Kp * Error + IntegralTerm + DerivativeTerm;

    IF Output < 0.0 THEN
        Output := 0.0;
    ELSIF Output > 100.0 THEN
        Output := 100.0;
    END_IF;

    ErrorPrev := Error;
END_IF;
END_FUNCTION_BLOCK

PROGRAM PumpLeadLag
VAR_INPUT
    LevelLow : BOOL;
    LevelHigh : BOOL;
    Pump1Fault : BOOL;
    Pump2Fault : BOOL;
    ManualMode : BOOL;
    ManualP1Run : BOOL;
    ManualP2Run : BOOL;
END_VAR
VAR_OUTPUT
    P1Run : BOOL;
    P2Run : BOOL;
END_VAR
VAR
    LeadPump : INT := 1;
END_VAR

(* Обновление ведущего насоса при авариях *)
IF Pump1Fault AND Pump2Fault THEN
    LeadPump := 1;
ELSIF Pump1Fault THEN
    LeadPump := 2;
ELSIF Pump2Fault THEN
    LeadPump := 1;
END_IF;

IF ManualMode THEN
    P1Run := ManualP1Run;
    P2Run := ManualP2Run;
ELSE
    IF LevelHigh THEN
        P1Run := FALSE;
        P2Run := FALSE;
    ELSIF LevelLow THEN
        P1Run := (LeadPump = 1);
        P2Run := (LeadPump = 2);
    ELSE
        P1Run := FALSE;
        P2Run := FALSE;
    END_IF;
END_IF;
END_PROGRAM

PROGRAM BatchDoseSequence
VAR_INPUT
    StartSeq : BOOL;
    Abort    : BOOL;
END_VAR
VAR_OUTPUT
    Valve1   : BOOL;
    Valve2   : BOOL;
    Valve3   : BOOL;
    SeqDone  : BOOL;
    SeqActive: BOOL;
END_VAR
VAR
Step      : INT := 0;
    T1        : TON;
    T2        : TON;
    T3        : TON;
END_VAR

IF Abort THEN
    Step := 0;
    Valve1 := FALSE;
    Valve2 := FALSE;
    Valve3 := FALSE;
    SeqDone := FALSE;
    SeqActive := FALSE;
    T1(IN := FALSE);
    T2(IN := FALSE);
    T3(IN := FALSE);
ELSE
    CASE Step OF
        0:
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            SeqDone := FALSE;
            SeqActive := FALSE;
            IF StartSeq THEN
                Step := 1;
            END_IF;
        1:
            SeqActive := TRUE;
            Valve1 := TRUE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            T1(PT := T#2S);
            IF T1.Q THEN
                Step := 2;
            END_IF;
        2:
            SeqActive := TRUE;
            Valve1 := FALSE;
            Valve2 := TRUE;
            Valve3 := FALSE;
            T2(PT := T#3S);
            IF T2.Q THEN
                Step := 3;
            END_IF;
        3:
            SeqActive := TRUE;
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := TRUE;
            T3(PT := T#1S);
            IF T3.Q THEN
                Step := 4;
            END_IF;
        4:
            SeqActive := FALSE;
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            SeqDone := TRUE;
    END_CASE;
END_IF;
END_PROGRAM

PROGRAM SafetyInterlock
VAR_INPUT
    EStopOK : BOOL;
    GuardClosed : BOOL;
    ResetPB : BOOL;
END_VAR

VAR_OUTPUT
    MachineEnable : BOOL;
    SafetyFault : BOOL;
END_VAR

VAR
    ResetTrig : R_TRIG;
END_VAR

(* Rising edge detection for ResetPB *)
ResetTrig(CLK := ResetPB);

(* SafetyFault latch logic *)
IF NOT EStopOK OR NOT GuardClosed THEN
    SafetyFault := TRUE;
ELSIF ResetTrig.Q AND EStopOK AND GuardClosed THEN
    SafetyFault := FALSE;
END_IF;

(* MachineEnable output logic *)
MachineEnable := NOT SafetyFault AND EStopOK AND GuardClosed;

END_PROGRAM

PROGRAM ProductionCounter
VAR_INPUT
    ProductSensor : BOOL;
    ResetBatch : BOOL;
    BatchTarget : INT := 1000;
END_VAR

VAR_OUTPUT
    BatchCount : INT;
    BatchComplete : BOOL;
    TotalCount : INT;
END_VAR

VAR
    SensorRising : R_TRIG;
    Counter : CTU;
END_VAR

(* Rising edge detection on ProductSensor *)
SensorRising(CLK := ProductSensor);

(* Batch counting: CTU with PV=BatchTarget, Reset=ResetBatch *)
Counter(CU := SensorRising.Q, PV := BatchTarget, R := ResetBatch);

(* Assign batch outputs *)
BatchCount := Counter.CV;
BatchComplete := Counter.Q;

(* Accumulative total count increments on every sensor pulse *)
IF SensorRising.Q THEN
    TotalCount := TotalCount + 1;
END_IF;
END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
    Enable : BOOL;
    RawInput : REAL;
    WindowSize : INT;
END_VAR
VAR_OUTPUT
    Filtered : REAL;
END_VAR
VAR
    Buffer : ARRAY[0..9] OF REAL;
    Head : INT;
    Count : INT;
    Sum : REAL;
    EffectiveSize : INT;
END_VAR

IF NOT Enable THEN
    Head := 0;
    Count := 0;
    Sum := 0.0;
    Filtered := 0.0;
ELSE
    EffectiveSize := MAX(1, MIN(10, WindowSize));
    IF Count < EffectiveSize THEN
        Buffer[Head] := RawInput;
        Sum := Sum + RawInput;
        Count := Count + 1;
        Head := (Head + 1) MOD EffectiveSize;
    ELSE
        Sum := Sum - Buffer[Head] + RawInput;
        Buffer[Head] := RawInput;
        Head := (Head + 1) MOD EffectiveSize;
    END_IF;
    Filtered := Sum / INT_TO_REAL(Count);
END_IF;
END_FUNCTION_BLOCK
